  "visitScheduleRule": "\"use strict\";\n({ params, imports }) => {\n  const encounter = params.entity;\n  const moment = imports.moment;\n  const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({\n    encounter\n  });\n\n  // Add new visit schedule object to scheduleBuilder\n  const scheduledOrCompletedEncountersOfType = (type, nextVisitDate) => {\n    const nextDateMonth = moment(nextVisitDate).add(6, 'hours').month();\n    console.log('nextDateMonth------->',nextDateMonth);\n    const nextDateYear = moment(nextVisitDate).add(6, 'hours').year();\n    console.log('nextDateYear------->',nextDateYear);\n    const data = encounter.individual.encounters.filter(\n      (enc) =>\n        enc.encounterType.name === type &&\n        enc.voided == false &&\n        enc.cancelDateTime == null &&\n        moment(enc.earliestVisitDateTime).add(6, 'hours').year() == nextDateYear &&\n        moment(enc.earliestVisitDateTime).add(6, 'hours').month() == nextDateMonth\n    );\n    console.log('data--------->',data);\n    return data;\n  };\n\n  const msm_date = moment(encounter.earliestVisitDateTime)\n    .add(6, 'hours')\n    .add(1, 'months')\n    .startOf('month')\n    .add(6, 'hours')\n    .toDate();\n    console.log('msm_date--------->',msm_date);\n    \n  const condition11 = scheduledOrCompletedEncountersOfType(\n    \"School Teacher Capacity Building\",\n    msm_date\n  ).length > 0;\n\n  if (!condition11) {\n    const earliestDate = msm_date;\n    const maxDate = moment(earliestDate).add(25, \"d\").toDate();\n    scheduleBuilder.add({\n      name: \"School Teacher Capacity Building\",\n      encounterType: \"School Teacher Capacity Building\",\n      earliestDate,\n      maxDate\n    });\n  }\n\n  return scheduleBuilder.getAll();\n};",
