({params, imports}) => {
    const encounter = params.entity;
    const formElement = params.formElement;
    const statusBuilder = new imports.rulesConfig.FormElementStatusBuilder({encounter, formElement});

    let childNeedHealthCheckup = encounter.getObservationReadableValue("Does any child need a health checkup");
    console.log('areChildPresent',childNeedHealthCheckup);
    let showCondition = _.isEqual(childNeedHealthCheckup, 'Yes');
    console.log('showCondition',showCondition);
    const groupSubject = params.entity.individual.groupSubjects;
    const children = [];

    groupSubject.forEach((e) => {
        if (!e.voided) {
            children.push(e.memberSubject.uuid);
            statusBuilder.showAnswers(e.memberSubject.uuid);
        }
    });


    statusBuilder.show().whenItem(showCondition).is.truthy;
    return statusBuilder.build();
};

