  "decisionRule": "\"use strict\";\n({params, imports}) => {\n    const programEncounter = params.entity;\n    const moment = imports.moment;\n    const _ = imports.lodash;\n    const decisions = params.decisions;\n    const enrolmentDecisions = [];\n    const encounterDecisions = [];\n    const registrationDecisions = [];\n    \n    let encDateTime = programEncounter.encounterDateTime;\n    let momentDate = moment(encDateTime);\n    \n    let year = momentDate.year(); \n    let month = momentDate.month() + 1; \n    let homeoTreatmentNumber = (year * 100)+month;\n\n    encounterDecisions.push({name: \"Homeo Treatment Number\", value: homeoTreatmentNumber});  \n    \n    \n    const height = programEncounter.getObservationValue(\"Height\");\n    const weight = programEncounter.getObservationValue(\"Weight\");\n    const asOnDate = programEncounter.encounterDateTime;\n    const individual = programEncounter.programEnrolment.individual;\n    const age = programEncounter.programEnrolment.individual.getAgeInMonths();\n    \n    const getGradeforZscore = (zScore) => {\n        let grade;\n        if (zScore <= -3) {\n            grade = 3;\n        } else if (zScore > -3 && zScore < -2) {\n            grade = 2;\n        } else if (zScore >= -2) {\n            grade = 1;\n        }\n        return grade;\n    };\n    \n    const zScoresForChild = ruleServiceLibraryInterfaceForSharingModules.common.getZScore(individual, asOnDate, weight, height);\n\n    /*Weight for age*/\n    const zScoreGradeStatusMappingWeightForAge = {\n      '1': 'Green',\n      '2': 'Yellow',\n      '3': 'Red'\n    };\n    \n    const wfaGrade = getGradeforZscore(zScoresForChild.wfa);\n    const wfaStatus = zScoreGradeStatusMappingWeightForAge[wfaGrade];\n    const wfaZScore= zScoresForChild.wfa;\n    \n    encounterDecisions.push({name: \"Z-Score Gradation Value (Weight for Age)\", value: wfaZScore});\n    encounterDecisions.push({name: \"Z-Score Gradation Colour (Weight for Age)\", value: wfaStatus});  \n    \n    /*Weight for age*/\n    \n    /*Height for age*/\n    const zScoreGradeStatusMappingHeightForAge = {\n      '1': 'Normal Height',\n      '2': 'Stunted',\n      '3': 'Severely Stunted'\n    };\n\n    const hfaGrade = getGradeforZscore(zScoresForChild.hfa);\n    const hfaZScore = zScoresForChild.hfa;\n    const hfaStatus = zScoreGradeStatusMappingHeightForAge[hfaGrade];\n    \n    encounterDecisions.push({name: \"Z-Score Gradation Value (Height for Age)\", value: hfaZScore});\n    encounterDecisions.push({name: \"Z-Score Gradation Category (Height for Age)\", value: hfaStatus});  \n    /*Height for age*/\n    \n    \n    /*Weight for height*/\n    const zScoreGradeStatusMappingWeightForHeight = {\n      '1': 'Normal',\n      '2': 'Moderate Wasting',\n      '3': 'Severe Wasting'\n    };\n    \n    const wfhGrade = getGradeforZscore(zScoresForChild.wfh);\n    const wfhStatus = zScoreGradeStatusMappingWeightForHeight[wfhGrade];\n    const wfhZScore = zScoresForChild.wfh;\n    \n    \n    encounterDecisions.push({name: \"Z-Score Gradation Value (Weight for Height)\", value: wfhZScore});\n    encounterDecisions.push({name: \"Z-Score Gradation Category (Weight for Height)\", value: wfhStatus});  \n    /*Weight for height*/ \n    \n    decisions.enrolmentDecisions.push(...enrolmentDecisions);\n    decisions.encounterDecisions.push(...encounterDecisions);\n    decisions.registrationDecisions.push(...registrationDecisions);\n    return decisions;\n};",
