  "visitScheduleRule": "\"use strict\";\n({ params, imports }) => {\n    const programEncounter = params.entity;\n    const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({ programEncounter });\n    const moment = imports.moment;\n    const encounterType = programEncounter.encounterType.name;\n\n    // Get the follow-up date from the encounter observation\n    const followUpDateValue = programEncounter.findCancelEncounterObservation('Select date of next visit');\n    if (!followUpDateValue) {\n        return scheduleBuilder.getAll();\n    }\n\n    const isActive = !programEncounter.programEnrolment.programExitDateTime;\n    if (!isActive) {\n        return scheduleBuilder.getAll();\n    }\n\n    const followUpDate = moment(followUpDateValue.getValue()).startOf('day');\n\n    // Check if an encounter of the same type is already scheduled on the same date for this subject\n    const existingEncounters = programEncounter.programEnrolment.getEncountersOfType(encounterType);\n\n    const isAlreadyScheduled = existingEncounters.some(enc =>\n        moment(enc.earliestVisitDateTime).startOf('day').isSame(followUpDate, 'day')\n    );\n\n    if (!isAlreadyScheduled) {\n    \n        const earliestDate = followUpDate.toDate();\n        const maxDate = moment(earliestDate).add(1, 'days').endOf('day').toDate();\n        scheduleBuilder.add({\n            name: encounterType,\n            encounterType: encounterType,\n            earliestDate: earliestDate,\n            maxDate: maxDate\n        });\n    }\n\n    return scheduleBuilder.getAll();\n};",
