({params, imports}) => {
    const encounter = params.entity;
    const moment = imports.moment;
    const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({encounter});

    const visitDate = encounter.earliestVisitDateTime || encounter.cancelDateTime;

    const nextDate = moment(visitDate)
        .utcOffset("+05:30")
        .add(1, "month")
        .startOf("month")
        .utc();

    const hasScheduledOrCompletedEncounterOfType = (type, nextVisitDate) => {
        const nextMonth = nextVisitDate.month();
        const nextYear = nextVisitDate.year();
                         console.log("nextMonth--->", nextMonth)
                         console.log("nextYear--->", nextYear)

        return encounter.individual.encounters.some(enc => {
            if (enc.voided || enc.encounterType.name != type) return false;

            const encDate = enc.earliestVisitDateTime || enc.encounterDateTime || enc.cancelDateTime;
            if (!encDate) return false;
           console.log("\n \n ENC DATE--->", encDate )
            const normalized = moment(encDate)
                .utcOffset("+05:30")
                .startOf("month")
                .utc();
           console.log("normalized.year()--->", normalized.year())

        console.log("normalized.month()------->", normalized.month())


            return normalized.year() == nextYear && normalized.month() == nextMonth;

        });
    }

    const alreadyExists = hasScheduledOrCompletedEncounterOfType("Library Monthly Report", nextDate);
console.log("ALREADY--------------->", alreadyExists)
    if (!alreadyExists) {
        const earliestDate = nextDate.toDate();
        const maxDate = moment(earliestDate).add(25, "days").toDate();

        scheduleBuilder.add({
            name: "Library Monthly Report",
            encounterType: "Library Monthly Report",
            earliestDate,
            maxDate
        });
    }

    return scheduleBuilder.getAll();
